/**
 * Password Token API Service
 *
 * Handles API calls for password view tokens (T047).
 */

import axios from 'axios';

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:3000';

export interface ViewPasswordResponse {
  password: string;
  userId: string;
  viewed: boolean;
}

/**
 * View password via one-time token
 *
 * @param token - 128-char hex token
 * @returns Password, user ID, and viewed status
 * @throws 400 - Invalid token format
 * @throws 404 - Token not found or expired
 * @throws 410 - Token already viewed
 */
export const viewPassword = async (token: string): Promise<ViewPasswordResponse> => {
  const response = await axios.get<ViewPasswordResponse>(`${API_URL}/password-tokens/${token}`);
  return response.data;
};
