/**
 * ViewPasswordPage Component (T047)
 *
 * パスワード表示ページ。
 * URLパラメータからトークンを取得し、一時パスワードを表示します。
 *
 * ルート: /view-password/:token
 *
 * セキュリティ機能:
 * - ワンタイム表示（一度表示すると再表示不可）
 * - 24時間有効期限
 * - クリップボードコピー機能
 */

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { usePasswordToken } from '../hooks/usePasswordToken';
import { Navbar } from '../components';
import { isAxiosError, getAxiosErrorResponse } from '../utils/errors';

/**
 * ViewPasswordPageコンポーネント
 * パスワード表示とコピー機能を提供します
 */
const ViewPasswordPage: React.FC = () => {
  const navigate = useNavigate();
  const { viewPassword } = usePasswordToken();
  const { token } = useParams<{ token: string }>();
  const hasFetched = useRef(false); // Prevent double-fetch in React 18 Strict Mode

  const [isLoading, setIsLoading] = useState(true);
  const [password, setPassword] = useState<string | null>(null);
  const [userId, setUserId] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [errorType, setErrorType] = useState<
    'not-found' | 'already-viewed' | 'invalid' | 'generic' | null
  >(null);
  const [copied, setCopied] = useState(false);

  /**
   * パスワード取得
   */
  useEffect(() => {
    // Prevent double-fetch in React 18 Strict Mode (development)
    if (hasFetched.current) return;
    hasFetched.current = true;

    const fetchPassword = async () => {
      if (!token) {
        setIsLoading(false);
        setErrorType('invalid');
        setErrorMessage('トークンが指定されていません。');
        return;
      }

      // Validate token format (128-char hex)
      if (!/^[0-9a-fA-F]{128}$/.test(token)) {
        setIsLoading(false);
        setErrorType('invalid');
        setErrorMessage(
          '無効なトークン形式です。トークンは128文字の16進数文字列である必要があります。'
        );
        return;
      }

      try {
        const result = await viewPassword(token);
        setPassword(result.password);
        setUserId(result.userId);
      } catch (error: unknown) {
        if (isAxiosError(error)) {
          const response = getAxiosErrorResponse(error);
          const status = response?.status;
          const message =
            (response?.data as { message?: string })?.message || 'パスワードの取得に失敗しました。';

          if (status === 404) {
            setErrorType('not-found');
            setErrorMessage('トークンが見つからないか、期限切れです。トークンは24時間有効です。');
          } else if (status === 410) {
            setErrorType('already-viewed');
            setErrorMessage(
              'このパスワードリンクは既に表示されています。セキュリティ上の理由により、一度しかアクセスできません。'
            );
          } else if (status === 400) {
            setErrorType('invalid');
            setErrorMessage(message);
          } else {
            setErrorType('generic');
            setErrorMessage('パスワードの取得中にエラーが発生しました。もう一度お試しください。');
          }
        } else {
          setErrorType('generic');
          setErrorMessage('予期しないエラーが発生しました。');
        }
      } finally {
        setIsLoading(false);
      }
    };

    fetchPassword();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  /**
   * クリップボードにコピー
   */
  const handleCopy = async () => {
    if (!password) return;

    try {
      await navigator.clipboard.writeText(password);
      setCopied(true);

      // 2秒後にコピー済み表示をリセット
      setTimeout(() => setCopied(false), 2000);
    } catch (error) {
      console.error('Failed to copy password:', error);
      alert('パスワードのコピーに失敗しました。手動でコピーしてください。');
    }
  };

  /**
   * 読み込み中の表示
   */
  if (isLoading) {
    return (
      <>
        <Navbar />
        <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
          <div className="sm:mx-auto sm:w-full sm:max-w-md">
            <div className="bg-white py-8 px-4 shadow-lg sm:rounded-lg sm:px-10">
              <div className="text-center">
                <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
                <p className="mt-4 text-gray-600">パスワードを取得しています...</p>
              </div>
            </div>
          </div>
        </div>
      </>
    );
  }

  /**
   * エラー表示
   */
  if (errorMessage) {
    return (
      <>
        <Navbar />
        <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
          <div className="sm:mx-auto sm:w-full sm:max-w-md">
            <div className="bg-white py-8 px-4 shadow-lg sm:rounded-lg sm:px-10">
              <div className="text-center">
                {/* Error icon */}
                <div className="mx-auto flex items-center justify-center h-12 w-12 rounded-full bg-red-100">
                  <svg
                    className="h-6 w-6 text-red-600"
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M6 18L18 6M6 6l12 12"
                    />
                  </svg>
                </div>

                {/* Error message */}
                <h2 className="mt-4 text-xl font-bold text-gray-900">
                  {errorType === 'not-found' && 'トークンが見つかりません'}
                  {errorType === 'already-viewed' && '既に表示されています'}
                  {errorType === 'invalid' && '無効なトークン'}
                  {errorType === 'generic' && 'エラーが発生しました'}
                </h2>
                <p className="mt-2 text-sm text-gray-600">{errorMessage}</p>

                {/* Action button */}
                <div className="mt-6">
                  <button
                    onClick={() => navigate('/login')}
                    className="w-full inline-flex justify-center rounded-md border border-transparent shadow-sm px-4 py-2 bg-primary-600 text-base font-medium text-white hover:bg-primary-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
                  >
                    ログインページへ
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </>
    );
  }

  /**
   * パスワード表示
   */
  return (
    <>
      <Navbar />
      <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
        <div className="sm:mx-auto sm:w-full sm:max-w-md">
          <div className="bg-white py-8 px-4 shadow-lg sm:rounded-lg sm:px-10">
            {/* Success icon */}
            <div className="text-center mb-6">
              <div className="mx-auto flex items-center justify-center h-12 w-12 rounded-full bg-green-100">
                <svg
                  className="h-6 w-6 text-green-600"
                  xmlns="http://www.w3.org/2000/svg"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M5 13l4 4L19 7"
                  />
                </svg>
              </div>
              <h2 className="mt-4 text-xl font-bold text-gray-900">一時パスワード</h2>
            </div>

            {/* Warning message */}
            <div className="mb-6 rounded-md bg-yellow-50 border-l-4 border-yellow-400 p-4">
              <div className="flex">
                <div className="flex-shrink-0">
                  <svg
                    className="h-5 w-5 text-yellow-400"
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 20 20"
                    fill="currentColor"
                  >
                    <path
                      fillRule="evenodd"
                      d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z"
                      clipRule="evenodd"
                    />
                  </svg>
                </div>
                <div className="ml-3">
                  <p className="text-sm text-yellow-700">
                    <strong>重要:</strong> このパスワードは一度しか表示されません。
                    必ずコピーして安全に保管してください。
                  </p>
                </div>
              </div>
            </div>

            {/* Password display */}
            <div className="mb-6">
              <label className="block text-sm font-medium text-gray-700 mb-2">パスワード</label>
              <div className="mt-1 flex rounded-md shadow-sm">
                <div className="flex-1 relative rounded-md border border-gray-300 bg-gray-50 px-4 py-3">
                  <code className="text-lg font-mono font-semibold text-gray-900 select-all">
                    {password}
                  </code>
                </div>
              </div>
            </div>

            {/* Copy button */}
            <div className="mb-6">
              <button
                onClick={handleCopy}
                className={`w-full inline-flex justify-center items-center rounded-md border border-transparent shadow-sm px-4 py-2 text-base font-medium text-white focus:outline-none focus:ring-2 focus:ring-offset-2 ${
                  copied
                    ? 'bg-green-600 hover:bg-green-700 focus:ring-green-500'
                    : 'bg-primary-600 hover:bg-primary-700 focus:ring-primary-500'
                }`}
              >
                {copied ? (
                  <>
                    <svg
                      className="mr-2 h-5 w-5"
                      xmlns="http://www.w3.org/2000/svg"
                      fill="none"
                      viewBox="0 0 24 24"
                      stroke="currentColor"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        strokeWidth={2}
                        d="M5 13l4 4L19 7"
                      />
                    </svg>
                    コピー済み!
                  </>
                ) : (
                  <>
                    <svg
                      className="mr-2 h-5 w-5"
                      xmlns="http://www.w3.org/2000/svg"
                      fill="none"
                      viewBox="0 0 24 24"
                      stroke="currentColor"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        strokeWidth={2}
                        d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z"
                      />
                    </svg>
                    パスワードをコピー
                  </>
                )}
              </button>
            </div>

            {/* Instructions */}
            <div className="rounded-md bg-blue-50 border border-blue-200 p-4">
              <h3 className="text-sm font-medium text-blue-800 mb-2">次のステップ:</h3>
              <ol className="list-decimal list-inside text-sm text-blue-700 space-y-1">
                <li>上記のパスワードをコピーしてください</li>
                <li>ログインページにアクセスしてください</li>
                <li>メールアドレスとこのパスワードでログインしてください</li>
                <li>ログイン後、パスワードを変更することをお勧めします</li>
              </ol>
            </div>

            {/* Login button */}
            <div className="mt-6">
              <button
                onClick={() => navigate('/login')}
                className="w-full inline-flex justify-center rounded-md border border-gray-300 shadow-sm px-4 py-2 bg-white text-base font-medium text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
              >
                ログインページへ
              </button>
            </div>

            {/* User ID (for debugging) */}
            {userId && (
              <div className="mt-4 text-center">
                <p className="text-xs text-gray-500">User ID: {userId}</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </>
  );
};

export default ViewPasswordPage;
